select.if:
select id, channelCode, channelName, customerType, channelAddr, remark, status, updatedTime, updaterName, chooseFlag, channelTotal from ( SELECT t.id AS id, t.channel_code AS channelCode, t.channel_name AS channelName, t.customer_type AS customerType, t.channel_addr AS channelAddr, t.remark AS remark, t.status AS status, t.updated_time AS updatedTime, t.creator_name AS updaterName, 0 AS chooseFlag, ( SELECT COUNT(1) FROM site_customer cc WHERE cc.channel_code = t.channel_code) AS channelTotal FROM customer_channel t) a WHERE a.channelTotal = 0
AND t.channel_name = #{vo.channelName}
AND t.channel_code = #{vo.channelCode}
ORDER BY channelTotal DESC, status DESC, updatedTime DESC

select id, channelCode, channelName, customerType, channelAddr, remark, status, updatedTime, updaterName, chooseFlag, channelTotal from ( SELECT t.id AS id, t.channel_code AS channelCode, t.channel_name AS channelName, t.customer_type AS customerType, t.channel_addr AS channelAddr, t.remark AS remark, t.status AS status, t.updated_time AS updatedTime, t.creator_name AS updaterName, 0 AS chooseFlag, ( SELECT COUNT(1) FROM site_customer cc WHERE cc.channel_code = t.channel_code) AS channelTotal FROM customer_channel t) a WHERE a.channelTotal = 0
AND a.channel_name = #{vo.channelName}
AND a.channel_code = #{vo.channelCode}
union all SELECT cc.id id, cc.channel_code as channelCode, cc.channel_name as channelName, cc.customer_type as customerType, cc.channel_addr as channelAddr, cc.remark, cc.status, sc.created_time as updatedTime, sc.creator as updaterName, 1 as chooseFlag, 1 as channelTotal from site_customer sc left join customer_channel cc on sc.channel_code = cc.channel_code where sc.site_code = #{vo.siteCode}
AND cc.channel_name = #{vo.channelName}
AND cc.channel_code = #{vo.channelCode}
order by chooseFlag desc

mapper.select:
SELECT a.id, a.channelCode as channelCode, a.channelName as channelName, a.customerType as customerType, a.channelAddr as channelAddr, a.`status` as status, a.operator as updaterName, a.operatorTime as updatedTime FROM ( SELECT t2.id AS id, t1.channel_code AS channelCode, t1.channel_name AS channelName, t1.customer_type AS customerType, t1.channel_addr AS channelAddr, t2.enable_status AS status, CASE WHEN t2.updated_time IS NOT NULL THEN t2.updated_time ELSE t2.created_time END AS operatorTime, CASE WHEN t2.updater IS NOT NULL THEN t2.updater ELSE t2.creator END AS operator FROM customer_channel t1, site_customer t2 WHERE t2.site_code = #{vo.siteCode} and t1.channel_code = t2.channel_code
AND t2.enable_status = #{vo.status}
AND t1.channel_name = #{vo.channelName}
AND t1.channel_code = #{vo.channelCode}
) a ORDER BY a.status DESC, a.operatorTime DESC

SELECT a.platformCode, a.channelCode, a.channelName, a.customerType, a.channelAddr FROM ( SELECT t1.platform_code as platformCode, t1.channel_code AS channelCode, t1.channel_name AS channelName, t1.customer_type AS customerType, t1.channel_addr AS channelAddr, CASE WHEN t2.updated_time IS NOT NULL THEN t2.updated_time ELSE t2.created_time END AS operatorTime, CASE WHEN t2.updater IS NOT NULL THEN t2.updater ELSE t2.creator END AS operator FROM customer_channel t1, site_customer t2 WHERE t2.site_code = #{vo.siteCode} and t1.channel_code = t2.channel_code
AND t2.enable_status = #{vo.status}
) a ORDER BY a.operatorTime DESC limit 1

SELECT a.platformCode, a.channelCode, a.channelName, a.customerType, a.channelAddr, a.entId, a.groupToken, a.appKey, a.secretKey, a.extJson, a.status FROM ( SELECT t1.platform_code as platformCode, t1.channel_code AS channelCode, t1.channel_name AS channelName, t1.customer_type AS customerType, t1.channel_addr AS channelAddr, t1.mer_id as entId, t1.group_token as groupToken, t1.app_key as appKey, t1.secret_key as secretKey, t1.ext_json as extJson, t2.enable_status as status, CASE WHEN t2.updated_time IS NOT NULL THEN t2.updated_time ELSE t2.created_time END AS operatorTime, CASE WHEN t2.updater IS NOT NULL THEN t2.updater ELSE t2.creator END AS operator FROM customer_channel t1, site_customer t2 WHERE t2.site_code = #{vo.siteCode} and t1.channel_code = t2.channel_code
AND t2.enable_status = #{vo.status}
AND t1.platform_code = #{vo.platformCode}
) a ORDER BY a.operatorTime DESC
